var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"큭?!","JPN":"くっ！？","ENG":"Ugh?!","TWN":"唔？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"드디어 따라잡았군.","JPN":"やっと追いついたぜ。","ENG":"Finally, I got you.","TWN":"終於被我抓到了吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"짧은 도주극에 대한 감상 좀 들어볼까, 도둑 기사 아가씨?","JPN":"短い逃走劇の感想を聞かせてくれるかい、泥棒騎士のお嬢ちゃん？","ENG":"Now, let’s hear your excuses, thieving knight girl.","TWN":"這麼短的時間內就被抓到，有什麼感想嗎，小偷騎士？"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"젠장, 조금만 천천히 가라니까! 그러다 또 낭패 보면 어쩌려고!","JPN":"おい、もう少しゆっくり行けよ！　無茶してまた逃げられたらどうすんだ！","ENG":"Hey, I told you to slow down! What if something unexpected happens again?","TWN":"該死的！就叫你走慢一點！萬一又搞砸的話怎麼辦！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"꾸물거리다 다시 놓치는 것보다는 낫지. 여기서 리액터를 회수한다.","JPN":"グズグズして逃がすよりマシだろ？　ここでリアクターを回収するぞ。","ENG":"It’s better than losing her trail. We will retrieve the reactor here and now.","TWN":"總比又被她逃掉的好吧！我要拿回反應爐！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"빌어먹을……. 군인들이란 하나같이 말이 안 통한다니까.","JPN":"くそ……軍人は本当に言葉が通じないな。","ENG":"Darn... You soldiers are all so thick-headed.","TWN":"有夠討厭的……軍人真的都很難溝通欸！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그나마 그쪽이 알려 준 발신기가 있어서 다행이었어.","JPN":"それにしても、教えてもらった発信機のおかげで助かった。","ENG":"We were lucky to have the transmitter in the machine, though.","TWN":"不過幸好你有告訴我們發射器的事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그거 아니었으면 이번 의뢰는 완전히 실패했을 거야.","JPN":"あれがなかったら今回の依頼は完全に失敗していただろう。","ENG":"If you didn’t tell us about it, we never would have found the reactor.","TWN":"否則這次的委託應該會失敗收場吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"별말씀을요. 그렇게 고마워하실 만큼 대단한 도움도 못 드렸는걸요.","JPN":"とんでもないです。お礼を言われるほどのことではありません。","ENG":"You’re welcome, but I don’t think I did much to help.","TWN":"不用客氣，我沒做什麼啦。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그렇게까지 자기 비하할 것 없어.","JPN":"そんなに自分を卑下する必要はないさ。","ENG":"Stop abasing yourself.","TWN":"你不用這麼謙卑！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나도 여러모로 심경이 복잡하긴 하지만……. 도움이 된 건 분명한 사실이야.","JPN":"まあ俺も複雑な心境だが……役に立ったのは事実だ。","ENG":"You know, it’s a bit confusing for me to say this too... But, you really did help us.","TWN":"雖然我的心情也有點複雜……不過你有幫上忙是事實！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"감사…… 합니다.","JPN":"ありがとう……ございます。","ENG":"Thank you...","TWN":"謝……謝你。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아저씨?!","JPN":"おじさん！？","ENG":"Mr. Mason?!","TWN":"大叔？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"음? 이 목소리는?","JPN":"うん？　この声は？","ENG":"Hmm? This voice?","TWN":"嗯？這個聲音是？ "},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"오랜만입니다, 메이슨 씨.","JPN":"お久しぶりです、メイソンさん。","ENG":"Hello, Mr. Mason.","TWN":"梅森，好久不見。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"코핀 컴퍼니 친구들이잖아. 이런 데서 다 만나는군.","JPN":"コフィンカンパニーのお仲間じゃないか。こんなところで会うとはな。","ENG":"My dear friends from the Coffin Company. I didn’t expect to see you here.","TWN":"這不是科芬公司的人嗎！沒想到會在這裡見到你們。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};